<template>

	<view class="components-form">
		<view :style="{paddingTop: vuex_custom_bar_height + 'px'}">

			<dynamic-demo-template ref="demoTemplate" :tips="tips" :sectionList="sectionList" :full="false"
				@click="click">
				<tn-form :model="form" ref="uForm" :errorType="['message']">


					<tn-form-item label="姓名" prop="name" :labelWidth="labelWidth" :labelAlign="labelAlign">
						<tn-input v-model="form.name" placeholder="请输入姓名" />

					</tn-form-item>

					<tn-form-item label="学号" prop="number" :labelWidth="labelWidth" :labelAlign="labelAlign">
						<tn-input v-model="form.number" placeholder="请输入学号/工号" />
					</tn-form-item>
					<tn-form-item label="手机号码" prop="phone" :labelWidth="140" :labelAlign="labelAlign"
						rightIcon="phone">
						<tn-input v-model="form.phone" placeholder="请输入手机号码" />
					</tn-form-item>
					<!-- <tn-form-item label="手机号码" prop="phone" rightIcon="phone" :labelPosition="labelPosition"
						:labelWidth="140">
						<tn-input v-model="model.phone" placeholder="请输入手机号码" :border="border">
						</tn-input>
					</tn-form-item> -->

					<tn-form-item label="班级" prop="stu_class" :labelWidth="labelWidth" :labelAlign="labelAlign">
						<tn-input v-model="form.stu_class" placeholder="请输入班级" />
					</tn-form-item>

					<tn-form-item label="楼栋" prop="dorm" :labelWidth="labelWidth" :labelAlign="labelAlign">
						<tn-input v-model="form.dorm" placeholder="请输入楼栋" />
					</tn-form-item>

				</tn-form>

				<tn-button margin="0rpx 0rpx 15rpx 0rpx" backgroundColor="#01BEFF" fontColor="#FFFFFF" width="100%"
					@click="submit">提交</tn-button>
			</dynamic-demo-template>
			<!-- <tn-picker mode="time" v-model="show" :params="params"></tn-picker> -->
			<!-- <tn-button @click="submit">提交</tn-button> -->
		</view>
	</view>
</template>

<script>
	import dynamicDemoTemplate from '@/libs/components/dynamic-demo-template.vue'
	import axios from 'axios'

	export default {
		components: {
			dynamicDemoTemplate
		},
		data() {
			return {


				user: [], //启动此个人信息页面创建一个user对象


				form: {
					name: '',
					phone: '',
					number: '',
					stu_class: '',
					dorm: '',

					hobby: [],
					radio: '',
					security: false

				}

			};
		},

		methods: {
			submit() {
				// 获取修改后的表单值
				const updatedUser = this.form;

				// 获取用户ID (如果你已经在this.user中存储了ID，否则从适当的地方获取它)
				const userId = this.user.id;

				uni.request({
					url: `http://localhost:8099/user/update/${userId}`,
					method: 'POST',
					data: JSON.stringify({
						// 要有id,接口才能查到
						id: userId,
						name: this.form.name,
						phone: this.form.phone,
						number: this.form.number,
						// 前面的名称要与实体类名称一致
						studentClass: this.form.stu_class,
						dorm: this.form.dorm
					}),

					header: {
						'content-type': 'application/json' // 请根据后端的需求设置适当的header
					},

					success: (res) => {
						console.log(res.data);
						console.log(userId);
						if (res.data.code == "0") { // 根据后端响应结构来调整这里
							// 成功处理
							uni.showToast({
								title: '更新成功',
								icon: 'success'
							});
						} else {
							// 处理失败情况
							uni.showToast({
								title: '更新失败',
								icon: 'none'
							});
						}
					},
					fail: (err) => {
						// 请求失败
						console.error("Error updating user:", err);
						uni.showToast({
							title: '请求失败',
							icon: 'none'
						});
					}
				});
			}


		},
		mounted() { //用于获取登录页面登录成功后从后台获取的用户信息
			//getItem读取sessionStorage里面key叫user的对象
			//JSON.parse获取的对象转为JSON格式获取
			// this.user = JSON.parse(sessionStorage.getItem("user"));
			this.user = JSON.parse(wx.getStorageSync("user"));
			this.form.name = this.user.name;
			this.form.phone = this.user.phone;
			this.form.number = this.user.userNumber;
			this.form.stu_class = this.user.studentClass;
			this.form.dorm = this.user.dorm;
		}
	}
</script>

<style lang="scss" scoped>
	.agreement {
		display: flex;
		align-items: center;
		margin: 40rpx 0;

		&-text {
			padding-left: 8rpx;
			color: $tn-font-sub-color;
		}
	}
</style>
